PRAGMA foreign_keys;
-- Habilitar el soporte de claves foráneas en SQLite
PRAGMA foreign_keys = ON;

/*
 * CREAR TABLAS
*/

/* 1. Tabla Lengua */
-- DROP TABLE IF EXISTS Lengua;
CREATE TABLE IF NOT EXISTS Lengua (
    codLengua_lg TEXT NOT NULL,	-- ISO Code (es, en)
	nombre_lg TEXT NOT NULL,
    CONSTRAINT PK_Lengua PRIMARY KEY (codLengua_lg)
);

/* 2. Tabla Version */
-- DROP TABLE IF EXISTS Version;
CREATE TABLE IF NOT EXISTS Version (
    codLengua_vs TEXT NOT NULL,
    codVersion_vs TEXT NOT NULL,
    nombre_vs TEXT NOT NULL,
    CONSTRAINT PK_Version PRIMARY KEY (codLengua_vs,
		codVersion_vs),
    CONSTRAINT FK_Version_Lengua FOREIGN KEY (codLengua_vs)
    	REFERENCES Lengua(codLengua_lg)	ON DELETE CASCADE
);

/* 3. Tabla Lectura (Contiene el plan de 365 días y el progreso)*/
-- DROP TABLE IF EXISTS Lectura;
CREATE TABLE IF NOT EXISTS Lectura (
    codLengua_ltr TEXT NOT NULL,
    codVersion_ltr TEXT NOT NULL,
    codLectura_ltr INTEGER NOT NULL CHECK (codLectura_ltr BETWEEN 1 AND 365), -- Representa el número de día (1-365)
	titulo_ltr TEXT NOT NULL,
    fecha_ltr DATE, -- Formato YYYY-MM-DD
	iframe_ltr TEXT NOT NULL DEFAULT 'https://youtu.be/9bWzrFcGPRo',
    completado_ltr INTEGER DEFAULT 0 CHECK (completado_ltr IN (0, 1)), -- 0 = Pendiente, 1 = Leído
	fechaProgreso_ltr DATE, -- Fecha en que se completó la lectura,
	alfaSiglaLibro_ltr TEXT NOT NULL,
    alfaCapitulo_ltr INTEGER NOT NULL,
    alfaVerso_ltr INTEGER NOT NULL,
    betaSiglaLibro_ltr TEXT NOT NULL,
    betaCapitulo_ltr INTEGER NOT NULL,
    betaVerso_ltr INTEGER NOT NULL,
    CONSTRAINT PK_Lectura PRIMARY KEY (codLengua_ltr, codVersion_ltr, codLectura_ltr),
    CONSTRAINT FK_Lectura_Version FOREIGN KEY (codLengua_ltr, codVersion_ltr)
    	REFERENCES Version(codLengua_vs, codVersion_vs) ON DELETE CASCADE
);

/* 4. Tabla Libro */
-- DROP TABLE IF EXISTS Libro;
CREATE TABLE IF NOT EXISTS Libro (
    codLengua_lb TEXT NOT NULL,
    codVersion_lb TEXT NOT NULL,
    codLibro_lb TEXT NOT NULL,
    numero_lb INTEGER NOT NULL,
    nombre_lb TEXT NOT NULL,
    CONSTRAINT PK_Libro PRIMARY KEY (codLengua_lb,
		codVersion_lb,
		codLibro_lb),
    CONSTRAINT FK_Libro_Version FOREIGN KEY (codLengua_lb,
		codVersion_lb)
        REFERENCES Version(codLengua_vs, codVersion_vs) ON DELETE CASCADE
);

/* 5. Tabla Capitulo */
-- DROP TABLE IF EXISTS Capitulo;
CREATE TABLE IF NOT EXISTS Capitulo (
    codLengua_cptl TEXT NOT NULL,
    codVersion_cptl TEXT NOT NULL,
    codLibro_cptl TEXT NOT NULL,
    codCapitulo_cptl INTEGER NOT NULL,
    CONSTRAINT PK_Capitulo PRIMARY KEY (codLengua_cptl, codVersion_cptl, codLibro_cptl, codCapitulo_cptl),
    CONSTRAINT FK_Capitulo_Libro FOREIGN KEY (codLengua_cptl, codVersion_cptl, codLibro_cptl) 
        REFERENCES Libro(codLengua_lb, codVersion_lb, codLibro_lb) ON DELETE CASCADE
);

/* 6. Tabla Versiculo */
-- DROP TABLE IF EXISTS Versiculo;
CREATE TABLE IF NOT EXISTS Versiculo (
    codLengua_vscl TEXT NOT NULL,
    codVersion_vscl TEXT NOT NULL,
    codLibro_vscl TEXT NOT NULL,
    codCapitulo_vscl INTEGER NOT NULL,
    codVersiculo_vscl INTEGER NOT NULL,
    encabezado_vscl TEXT,
    contenido_vscl TEXT NOT NULL,
    parrafo_vscl INTEGER DEFAULT 0,
	-- FK hacia Lectura (Plan fijo)
	codLengua_vscl_ltr TEXT,
    codVersion_vscl_ltr TEXT,
    codLectura_vscl_ltr INTEGER,
    CONSTRAINT PK_Versiculo PRIMARY KEY (codLengua_vscl, codVersion_vscl, codLibro_vscl, codCapitulo_vscl, codVersiculo_vscl),
    CONSTRAINT FK_Versiculo_Capitulo FOREIGN KEY (codLengua_vscl, codVersion_vscl, codLibro_vscl, codCapitulo_vscl) 
        REFERENCES Capitulo(codLengua_cptl, codVersion_cptl, codLibro_cptl, codCapitulo_cptl)
	        ON DELETE CASCADE,
	CONSTRAINT FK_Versiculo_Lectura FOREIGN KEY (codLengua_vscl_ltr, codVersion_vscl_ltr, codLectura_vscl_ltr) 
        REFERENCES Lectura(codLengua_ltr, codVersion_ltr, codLectura_ltr)
	        ON DELETE SET NULL);

/* 7. Tabla TipoRefrencia */
-- DROP TABLE IF EXISTS TipoReferencia;
CREATE TABLE IF NOT EXISTS TipoReferencia (
    codTipoReferencia_tprfrc INTEGER CONSTRAINT PK_TipoReferencia PRIMARY KEY AUTOINCREMENT,
    nombre_tprfrc TEXT NOT NULL
);

/* 8. Tabla Referencia */
-- DROP TABLE IF EXISTS Referencia;
CREATE TABLE IF NOT EXISTS Referencia (
    codLengua_rfrc_vscl TEXT NOT NULL,
    codVersion_rfrc_vscl TEXT NOT NULL,
    codLibro_rfrc_vscl TEXT NOT NULL,
    codCapitulo_rfrc_vscl INTEGER NOT NULL,
    codVersiculo_rfrc_vscl INTEGER NOT NULL,
    codTipoReferencia_rfrc_tprfrc INTEGER NOT NULL,
    codReferencia_rfrc INTEGER NOT NULL, -- ID secuencial de referencia por versiculo
    CONSTRAINT PK_Referencia PRIMARY KEY (codLengua_rfrc_vscl, codVersion_rfrc_vscl, codLibro_rfrc_vscl, codCapitulo_rfrc_vscl, codVersiculo_rfrc_vscl, codTipoReferencia_rfrc_tprfrc, codReferencia_rfrc),
    CONSTRAINT FK_Referencia_Versiculo FOREIGN KEY (codLengua_rfrc_vscl, codVersion_rfrc_vscl, codLibro_rfrc_vscl, codCapitulo_rfrc_vscl, codVersiculo_rfrc_vscl) 
        REFERENCES Versiculo(codLengua_vscl, codVersion_vscl, codLibro_vscl, codCapitulo_vscl, codVersiculo_vscl)
        	ON DELETE CASCADE,
	CONSTRAINT FK_Referencia_TipoReferencia FOREIGN KEY (codTipoReferencia_rfrc_tprfrc)
		REFERENCES TipoReferencia(codTipoReferencia_tprfrc)
			ON DELETE CASCADE
);

/* 9. Tabla VersiculoReferencia (Relación N:M para Versiclo - Referencia) */
-- DROP TABLE IF EXISTS VersiculoReferencia;
CREATE TABLE IF NOT EXISTS VersiculoReferencia (
	-- FK hacia Versículo (Origen)
	codLengua_vsclrfrc_vscl TEXT NOT NULL,
    codVersion_vsclrfrc_vscl TEXT NOT NULL,
    codLibro_vsclrfrc_vscl TEXT NOT NULL,
    codCapitulo_vsclrfrc_vscl INTEGER NOT NULL,
    codVersiculo_vsclrfrc_vscl INTEGER NOT NULL,
	-- FK hacia Referencia (Destino)
	codLengua_vsclrfrc_rfrc TEXT NOT NULL,
    codVersion_vsclrfrc_rfrc TEXT NOT NULL,
    codLibro_vsclrfrc_rfrc TEXT NOT NULL,
    codCapitulo_vsclrfrc_rfrc INTEGER NOT NULL,
    codVersiculo_vsclrfrc_rfrc INTEGER NOT NULL,
    codTipoReferencia_vsclrfrc_rfrc INTEGER NOT NULL,
    codReferencia_vsclrfrc_rfrc INTEGER NOT NULL,
    CONSTRAINT PK_VersiculoReferencia PRIMARY KEY (codLengua_vsclrfrc_vscl,	codVersion_vsclrfrc_vscl, codLibro_vsclrfrc_vscl, codCapitulo_vsclrfrc_vscl, codVersiculo_vsclrfrc_vscl, codLengua_vsclrfrc_rfrc, codVersion_vsclrfrc_rfrc, codLibro_vsclrfrc_rfrc, codCapitulo_vsclrfrc_rfrc, codVersiculo_vsclrfrc_rfrc, codTipoReferencia_vsclrfrc_rfrc, codReferencia_vsclrfrc_rfrc),
    CONSTRAINT FK_VersiculoReferencia_Versiculo FOREIGN KEY (codLengua_vsclrfrc_vscl, codVersion_vsclrfrc_vscl, codLibro_vsclrfrc_vscl, codCapitulo_vsclrfrc_vscl, codVersiculo_vsclrfrc_vscl) 
        REFERENCES Versiculo(codLengua_vscl, codVersion_vscl, codLibro_vscl, codCapitulo_vscl, codVersiculo_vscl)
        	ON DELETE CASCADE,
	CONSTRAINT FK_VersiculoReferencia_Referencia FOREIGN KEY (codLengua_vsclrfrc_rfrc, codVersion_vsclrfrc_rfrc, codLibro_vsclrfrc_rfrc, codCapitulo_vsclrfrc_rfrc, codVersiculo_vsclrfrc_rfrc, codTipoReferencia_vsclrfrc_rfrc, codReferencia_vsclrfrc_rfrc) 
        REFERENCES Referencia(codLengua_rfrc_vscl, codVersion_rfrc_vscl, codLibro_rfrc_vscl, codCapitulo_rfrc_vscl,	codVersiculo_rfrc_vscl,	codTipoReferencia_rfrc_tprfrc, codReferencia_rfrc)
	        ON DELETE CASCADE
);

/* TRIGGERS */
-- 7 Referencia
-- INSERT TR_ReferenciaInsert
-- DROP TRIGGER IF EXISTS TR_ReferenciaInsert;
CREATE TRIGGER IF NOT EXISTS TR_ReferenciaInsert
AFTER INSERT ON Referencia
FOR EACH ROW
WHEN NEW.codReferencia_rfrc IS NULL OR NEW.codReferencia_rfrc <= 0
BEGIN
    UPDATE Referencia
    SET codReferencia_rfrc = (
        SELECT COALESCE(MAX(codReferencia_rfrc), 0) + 1
        FROM Referencia
        WHERE codLengua_rfrc_vscl = NEW.codLengua_rfrc_vscl
          AND codVersion_rfrc_vscl = NEW.codVersion_rfrc_vscl
          AND codLibro_rfrc_vscl = NEW.codLibro_rfrc_vscl
          AND codCapitulo_rfrc_vscl = NEW.codCapitulo_rfrc_vscl
          AND codVersiculo_rfrc_vscl = NEW.codVersiculo_rfrc_vscl
          -- Nueva condición: El conteo es por tipo
          AND codTipoReferencia_rfrc_tprfrc = NEW.codTipoReferencia_rfrc_tprfrc
    )
    WHERE rowid = NEW.rowid;
END;

