/* 5. Insertar Capitulo */
-- DELETE FROM Capitulo;
-- SELECT * FROM Capitulo;
INSERT INTO Capitulo (codLengua_cptl, codVersion_cptl, codLibro_cptl, codCapitulo_cptl)
WITH RECURSIVE
  -- 1. Definimos los límites basados en la POSICIÓN CANÓNICA (1 al 66)
  -- Así no importa si se llama 'Gn', 'Gen' o '創世記' (Génesis en japonés)
  Limites(posicion, total) AS (
    VALUES
    (1, 50), (2, 40), (3, 27), (4, 36), (5, 34), (6, 24), (7, 21), (8, 4), (9, 31), (10, 24),
    (11, 22), (12, 25), (13, 29), (14, 36), (15, 10), (16, 13), (17, 10), (18, 42), (19, 150),
    (20, 31), (21, 12), (22, 8), (23, 66), (24, 52), (25, 5), (26, 48), (27, 12), (28, 14),
    (29, 3), (30, 9), (31, 1), (32, 4), (33, 7), (34, 3), (35, 3), (36, 3), (37, 2), (38, 14), (39, 4),
    (40, 28), (41, 16), (42, 24), (43, 21), (44, 28), (45, 16), (46, 16), (47, 13), (48, 6), (49, 6),
    (50, 4), (51, 4), (52, 5), (53, 3), (54, 6), (55, 4), (56, 3), (57, 1), (58, 13), (59, 5),
    (60, 5), (61, 3), (62, 5), (63, 1), (64, 1), (65, 1), (66, 22)
  ),
  -- 2. Generador de números (auxiliar)
  Generador(n) AS (
    SELECT 1 UNION ALL SELECT n + 1 FROM Generador WHERE n < 150
  )
-- 3. Unión por posición: Recuperamos las siglas reales de la tabla Libro
SELECT
    L.codLengua_lb,
    L.codVersion_lb,
    L.codLibro_lb, -- Aquí se insertará 'Gn', 'Ps', 'Mr', etc. según la versión
    G.n
FROM Libro L
JOIN Limites Lim ON L.numero_lb = Lim.posicion
JOIN Generador G ON G.n <= Lim.total
WHERE L.codVersion_lb = 'RVR1960'  -- <--- Parámetro de Versión
  AND L.codLengua_lb = 'spa'      -- <--- Parámetro de Idioma
ORDER BY L.numero_lb, G.n;

